No, hiding endpoints or features from the UI is **not a security control** - this is called "security by obscurity" and it provides zero actual protection. Attackers routinely discover hidden endpoints through browser dev tools, JavaScript source inspection, network traffic analysis, or simply guessing common paths.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// "Hidden" admin endpoints - NOT linked in UI
// Developer thinks these are secure because they're not visible
app.get('/api/secret-admin-panel', (req, res) => {
  // No authentication check!
  res.json({
    users: getAllUsers(),
    systemConfig: getSystemConfig(),
    apiKeys: getAllApiKeys()
  });
});

// "Hidden" user data export endpoint
app.get('/api/internal/export-all-users', (req, res) => {
  // Only "hidden" - no auth required
  const users = db.query('SELECT * FROM users');
  res.json(users);
});

// "Secret" debug endpoint with hardcoded path
app.get('/api/debug-12345', (req, res) => {
  res.json({
    env: process.env,
    dbConnectionString: process.env.DATABASE_URL,
    internalIPs: getInternalNetworkInfo()
  });
});

// Publicly accessible route that hints at hidden endpoints
app.get('/api/docs', (req, res) => {
  // JavaScript bundle includes references to all routes
  res.sendFile('api-docs.html');
});
```

**Attack Discovery Methods**:
```bash
# Method 1: Inspect JavaScript bundle
curl https://target.com/static/js/main.js | grep -E '/api/|endpoint|route'

# Method 2: Browser DevTools Network tab
# Watch all XHR requests during normal use

# Method 3: Fuzzing common admin paths
ffuf -u https://target.com/FUZZ -w /usr/share/wordlists/admin-paths.txt

# Method 4: Check robots.txt for "hidden" paths
curl https://target.com/robots.txt
```

**Why This Is Dangerous**:
- Hidden endpoints are trivially discoverable through client-side code inspection
- Automated tools like Burp Suite, OWASP ZAP, or ffuf find hidden paths in seconds
- No authentication means anyone who finds the URL has full access
- Sensitive data (API keys, env vars) exposed without any protection

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const { createLogger, transports } = require('winston');

const app = express();

const logger = createLogger({
  transports: [new transports.File({ filename: 'security-audit.log' })]
});

// Authentication middleware - REQUIRED for all protected routes
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    logger.warn(`Unauthenticated access attempt to ${req.path} from ${req.ip}`);
    return res.status(401).json({ error: 'Authentication required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      logger.warn(`Invalid token for ${req.path} from ${req.ip}`);
      return res.status(403).json({ error: 'Invalid token' });
    }
    req.user = user;
    next();
  });
};

// Authorization middleware - checks user roles
const requireRole = (allowedRoles) => {
  return (req, res, next) => {
    if (!req.user || !allowedRoles.includes(req.user.role)) {
      logger.warn(`Unauthorized access: User ${req.user?.id} attempted ${req.path}`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
};

// Rate limiting for admin endpoints
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// SECURE: Admin panel requires authentication AND admin role
app.get('/api/admin/dashboard',
  adminLimiter,
  authenticateToken,
  requireRole(['admin', 'superadmin']),
  (req, res) => {
    logger.info(`Admin dashboard accessed by user ${req.user.id}`);
    res.json({
      users: getAllUsersLimited(), // Only non-sensitive fields
      systemStatus: getPublicSystemStatus()
      // API keys NEVER exposed via API
    });
  }
);

// SECURE: User export requires authentication, admin role, and audit logging
app.get('/api/admin/export-users',
  adminLimiter,
  authenticateToken,
  requireRole(['superadmin']),
  (req, res) => {
    logger.info(`User export initiated by ${req.user.id} from ${req.ip}`);
    // Return only necessary fields, never passwords/tokens
    const users = db.query('SELECT id, email, created_at FROM users');
    res.json(users);
  }
);

// Debug endpoints DISABLED in production
if (process.env.NODE_ENV !== 'production') {
  app.get('/api/debug', authenticateToken, requireRole(['developer']), (req, res) => {
    res.json({ status: 'debug mode', requestId: req.id });
  });
}
```

**Key Security Controls**:
- **Authentication Required**: Every sensitive endpoint verifies JWT tokens before processing
- **Role-Based Authorization**: Admin functions require specific roles, not just authentication
- **Rate Limiting**: Prevents brute-force discovery and abuse
- **Audit Logging**: All access attempts are logged for forensic analysis
- **Environment Separation**: Debug endpoints completely disabled in production

Random URLs are **marginally better** than predictable paths but still fundamentally flawed as a security control. The Parler breach demonstrated this perfectly - their "unpredictable" URLs were still discoverable through JavaScript inspection. Random paths provide **obfuscation, not security**.

**Why Random URLs Fail**:
1. Client-side code must know the URL - it's in your JavaScript bundle
2. Browser history, logs, and referrer headers leak the URLs
3. One compromised user/insider reveals all "secret" paths
4. Proxy logs, CDN logs, and monitoring tools capture these URLs

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const { createLogger, transports, format } = require('winston');
const redis = require('redis');

const app = express();

// Security headers
app.use(helmet());
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'"],
    styleSrc: ["'self'"],
    imgSrc: ["'self'"],
    connectSrc: ["'self'"],
    frameSrc: ["'none'"]
  }
}));

// Structured audit logging
const auditLogger = createLogger({
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.File({ filename: 'audit.log' }),
    new transports.Console()
  ]
});

// Redis for session management and rate limiting
const redisClient = redis.createClient({
  url: process.env.REDIS_URL
});

// Multi-layer authentication middleware
const secureAuthentication = async (req, res, next) => {
  const requestId = crypto.randomUUID();
  req.requestId = requestId;

  try {
    // Layer 1: Token presence
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      auditLogger.warn({
        event: 'AUTH_MISSING',
        requestId,
        ip: req.ip,
        path: req.path,
        userAgent: req.headers['user-agent']
      });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const token = authHeader.split(' ')[1];

    // Layer 2: Token validation
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: 'myapp',
      audience: 'myapp-api'
    });

    // Layer 3: Token revocation check (prevents use of stolen tokens)
    const isRevoked = await redisClient.get(`revoked:${token}`);
    if (isRevoked) {
      auditLogger.warn({
        event: 'REVOKED_TOKEN_USED',
        requestId,
        userId: decoded.sub,
        ip: req.ip
      });
      return res.status(401).json({ error: 'Token revoked' });
    }

    // Layer 4: User status verification
    const user = await getUserById(decoded.sub);
    if (!user || user.status !== 'active') {
      auditLogger.warn({
        event: 'INACTIVE_USER_ACCESS',
        requestId,
        userId: decoded.sub,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Account inactive' });
    }

    req.user = user;
    next();
  } catch (err) {
    auditLogger.error({
      event: 'AUTH_ERROR',
      requestId,
      error: err.message,
      ip: req.ip
    });
    return res.status(401).json({ error: 'Invalid authentication' });
  }
};

// Granular permission checking
const checkPermission = (requiredPermission) => {
  return async (req, res, next) => {
    const userPermissions = await getUserPermissions(req.user.id);

    if (!userPermissions.includes(requiredPermission)) {
      auditLogger.warn({
        event: 'PERMISSION_DENIED',
        requestId: req.requestId,
        userId: req.user.id,
        required: requiredPermission,
        had: userPermissions,
        path: req.path
      });
      return res.status(403).json({ error: 'Permission denied' });
    }

    next();
  };
};

// IP-based access control for admin functions
const adminNetworkCheck = (req, res, next) => {
  const allowedNetworks = process.env.ADMIN_ALLOWED_IPS?.split(',') || [];
  const clientIP = req.ip;

  // In production, admin functions may require VPN/internal network
  if (process.env.NODE_ENV === 'production' && allowedNetworks.length > 0) {
    const isAllowed = allowedNetworks.some(network => 
      clientIP.startsWith(network.trim())
    );

    if (!isAllowed) {
      auditLogger.warn({
        event: 'ADMIN_NETWORK_VIOLATION',
        requestId: req.requestId,
        ip: clientIP,
        userId: req.user?.id
      });
      return res.status(403).json({ error: 'Access denied from this network' });
    }
  }
  next();
};

// Strict rate limiting for admin endpoints
const adminRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 50,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    auditLogger.warn({
      event: 'RATE_LIMIT_EXCEEDED',
      requestId: req.requestId,
      ip: req.ip,
      userId: req.user?.id,
      path: req.path
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// SECURE ADMIN ROUTES - Defense in depth, not obscurity
const adminRouter = express.Router();

// All admin routes require multiple security layers
adminRouter.use(adminRateLimiter);
adminRouter.use(secureAuthentication);
adminRouter.use(adminNetworkCheck);

adminRouter.get('/users',
  checkPermission('users:read'),
  async (req, res) => {
    auditLogger.info({
      event: 'ADMIN_USERS_LIST',
      requestId: req.requestId,
      userId: req.user.id,
      ip: req.ip
    });

    // Return only necessary, non-sensitive fields
    const users = await db.query(
      'SELECT id, email, created_at, last_login FROM users LIMIT 100'
    );
    res.json({ users, requestId: req.requestId });
  }
);

adminRouter.delete('/users/:id',
  checkPermission('users:delete'),
  async (req, res) => {
    const targetUserId = parseInt(req.params.id, 10);

    // Prevent self-deletion
    if (targetUserId === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete own account' });
    }

    auditLogger.info({
      event: 'ADMIN_USER_DELETE',
      requestId: req.requestId,
      adminId: req.user.id,
      targetUserId,
      ip: req.ip
    });

    await db.query('UPDATE users SET status = $1 WHERE id = $2', ['deleted', targetUserId]);
    res.json({ success: true, requestId: req.requestId });
  }
);

// Mount admin routes - path is public, security is in the middleware
app.use('/api/admin', adminRouter);

// Health check for monitoring - no sensitive data
app.get('/api/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT validation with issuer/audience verification, plus token revocation checking
```javascript
const decoded = jwt.verify(token, process.env.JWT_SECRET, {
  algorithms: ['HS256'],
  issuer: 'myapp',
  audience: 'myapp-api'
});
```

2. **Authorization Layer**: Granular permission system, not just role-based
```javascript
const userPermissions = await getUserPermissions(req.user.id);
if (!userPermissions.includes(requiredPermission)) {
  // Deny access
}
```

3. **Network Layer**: Admin functions restricted by IP/network in production
```javascript
if (process.env.NODE_ENV === 'production' && allowedNetworks.length > 0) {
  const isAllowed = allowedNetworks.some(network => 
    clientIP.startsWith(network.trim())
  );
}
```

**Additional Protections**:
- **Comprehensive Audit Logging**: Every admin action logged with request ID, user ID, IP, and timestamp for forensic analysis
- **Rate Limiting**: Prevents automated attacks even if authentication is somehow bypassed
- **Security Headers**: CSP, HSTS, X-Frame-Options prevent client-side attacks
- **Token Revocation**: Stolen tokens can be immediately invalidated
- **Environment Separation**: Debug endpoints completely removed from production builds
- **Principle of Least Privilege**: Users only get minimum permissions needed

Your endpoint likely has a critical authorization vulnerability. Missing authorization checks allow any authenticated user to access resources belonging to other users - this is called Insecure Direct Object Reference (IDOR) combined with missing authorization.

**VULNERABLE CODE**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.sql.*;

@Path("/api/documents")
public class DocumentController {

    private static final String DB_URL = "jdbc:postgresql://localhost/docdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @GET
    @Path("/{documentId}")
    @Produces(MediaType.APPLICATION_JSON)
    public Response getDocument(@PathParam("documentId") int documentId) {
        // VULNERABLE: No authorization check - any user can access any document
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT * FROM documents WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                Document doc = new Document();
                doc.setId(rs.getInt("id"));
                doc.setTitle(rs.getString("title"));
                doc.setContent(rs.getString("content"));
                doc.setOwnerId(rs.getInt("owner_id"));
                return Response.ok(doc).build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (SQLException e) {
            return Response.serverError().build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    public Response deleteDocument(@PathParam("documentId") int documentId) {
        // VULNERABLE: Any authenticated user can delete any document
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM documents WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.executeUpdate();
            return Response.noContent().build();
        } catch (SQLException e) {
            return Response.serverError().build();
        }
    }
}
```

**Attack Payload**:
```bash
# Attacker (User ID: 999) accessing another user's document
curl -X GET "https://api.example.com/api/documents/1" \
  -H "Authorization: Bearer <attacker_token>"

# Attacker deleting another user's document
curl -X DELETE "https://api.example.com/api/documents/1" \
  -H "Authorization: Bearer <attacker_token>"

# Enumeration attack to find all documents
for i in {1..10000}; do
  curl -s "https://api.example.com/api/documents/$i" \
    -H "Authorization: Bearer <token>" >> harvested_docs.json
done
```

**Why This Is Dangerous**:
- Any authenticated user can read ANY document by guessing/incrementing document IDs
- No verification that the requesting user owns or has permission to access the resource
- DELETE endpoint allows mass deletion of other users' data
- Sequential IDs make enumeration attacks trivial
- Violates the principle of least privilege

**SECURE VERSION**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.inject.Inject;
import java.sql.*;
import java.util.logging.Logger;

@Path("/api/documents")
public class SecureDocumentController {

    private static final Logger LOGGER = Logger.getLogger(SecureDocumentController.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/docdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Inject
    private SecurityContext securityContext;

    @Inject
    private AuthorizationService authService;

    @GET
    @Path("/{documentId}")
    @Produces(MediaType.APPLICATION_JSON)
    public Response getDocument(@PathParam("documentId") int documentId) {
        // Get current authenticated user
        String currentUserId = securityContext.getUserPrincipal().getName();

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // SECURE: Query includes owner check OR permission check
            String sql = "SELECT d.* FROM documents d " +
                        "LEFT JOIN document_permissions dp ON d.id = dp.document_id " +
                        "WHERE d.id = ? AND (d.owner_id = ? OR dp.user_id = ?)";

            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.setInt(2, Integer.parseInt(currentUserId));
            stmt.setInt(3, Integer.parseInt(currentUserId));
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                Document doc = new Document();
                doc.setId(rs.getInt("id"));
                doc.setTitle(rs.getString("title"));
                doc.setContent(rs.getString("content"));

                LOGGER.info(String.format("User %s accessed document %d", currentUserId, documentId));
                return Response.ok(doc).build();
            }

            // Log potential unauthorized access attempt
            LOGGER.warning(String.format("User %s denied access to document %d", currentUserId, documentId));
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Access denied").build();

        } catch (SQLException e) {
            LOGGER.severe("Database error: " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    public Response deleteDocument(@PathParam("documentId") int documentId) {
        String currentUserId = securityContext.getUserPrincipal().getName();

        // SECURE: Only owner can delete
        if (!authService.isDocumentOwner(currentUserId, documentId)) {
            LOGGER.warning(String.format("Unauthorized delete attempt: User %s on document %d", 
                          currentUserId, documentId));
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Only document owner can delete").build();
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM documents WHERE id = ? AND owner_id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.setInt(2, Integer.parseInt(currentUserId));

            int affected = stmt.executeUpdate();
            if (affected > 0) {
                LOGGER.info(String.format("User %s deleted document %d", currentUserId, documentId));
                return Response.noContent().build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (SQLException e) {
            LOGGER.severe("Database error: " + e.getMessage());
            return Response.serverError().build();
        }
    }
}
```

**Key Security Controls**:
- **Resource-level authorization**: Every request verifies the user has permission to access the specific resource
- **Defense in depth SQL**: Query includes owner/permission check even if service-layer check is bypassed
- **Audit logging**: All access attempts (successful and denied) are logged for security monitoring
- **Fail secure**: Returns 403 Forbidden with generic message, not revealing if resource exists

Complex authorization requires a dedicated authorization service with role-based access control (RBAC), attribute-based access control (ABAC), or a combination. Here's a production-ready pattern implementing hierarchical permissions.

**PRODUCTION PATTERN**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.inject.Inject;
import javax.annotation.security.RolesAllowed;
import java.sql.*;
import java.util.*;
import java.util.logging.Logger;
import java.time.Instant;

// Authorization Service - Central permission logic
public class AuthorizationService {

    private static final Logger AUDIT_LOG = Logger.getLogger("SECURITY_AUDIT");

    public enum Permission {
        READ, WRITE, DELETE, SHARE, ADMIN
    }

    public enum Role {
        ADMIN(100),           // Can do anything
        TEAM_LEAD(50),        // Can manage team resources
        MEMBER(10),           // Can access own and shared resources
        VIEWER(1);            // Read-only access

        private final int level;
        Role(int level) { this.level = level; }
        public int getLevel() { return level; }
    }

    @Inject
    private PermissionRepository permissionRepo;

    @Inject
    private TeamRepository teamRepo;

    public AuthorizationResult authorize(AuthorizationRequest request) {
        String userId = request.getUserId();
        String resourceId = request.getResourceId();
        String resourceType = request.getResourceType();
        Permission requiredPermission = request.getRequiredPermission();

        // Layer 1: Check if user is system admin
        if (isSystemAdmin(userId)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_ADMIN");
            return AuthorizationResult.granted("System admin access");
        }

        // Layer 2: Check direct ownership
        if (isResourceOwner(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_OWNER");
            return AuthorizationResult.granted("Resource owner");
        }

        // Layer 3: Check explicit user permissions
        Optional<Permission> directPermission = getDirectPermission(userId, resourceId, resourceType);
        if (directPermission.isPresent() && hasRequiredAccess(directPermission.get(), requiredPermission)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_DIRECT");
            return AuthorizationResult.granted("Direct permission");
        }

        // Layer 4: Check team-based permissions
        List<String> userTeams = teamRepo.getTeamsForUser(userId);
        for (String teamId : userTeams) {
            Optional<Permission> teamPermission = getTeamPermission(teamId, resourceId, resourceType);
            if (teamPermission.isPresent() && hasRequiredAccess(teamPermission.get(), requiredPermission)) {
                logAccess(userId, resourceId, requiredPermission, "GRANTED_TEAM:" + teamId);
                return AuthorizationResult.granted("Team permission via " + teamId);
            }
        }

        // Layer 5: Check hierarchical access (team lead can access team member resources)
        if (isTeamLeadWithAccessToMember(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_HIERARCHY");
            return AuthorizationResult.granted("Team lead hierarchical access");
        }

        // Default deny
        logAccess(userId, resourceId, requiredPermission, "DENIED");
        return AuthorizationResult.denied("Insufficient permissions");
    }

    private boolean hasRequiredAccess(Permission granted, Permission required) {
        Map<Permission, Integer> levels = Map.of(
            Permission.READ, 1,
            Permission.WRITE, 2,
            Permission.DELETE, 3,
            Permission.SHARE, 4,
            Permission.ADMIN, 5
        );
        return levels.get(granted) >= levels.get(required);
    }

    private void logAccess(String userId, String resourceId, Permission permission, String result) {
        AUDIT_LOG.info(String.format(
            "AUTH|%s|user=%s|resource=%s|permission=%s|result=%s|ip=%s",
            Instant.now().toString(), userId, resourceId, permission, result,
            RequestContext.getCurrentRemoteAddr()
        ));
    }

    private boolean isSystemAdmin(String userId) {
        return permissionRepo.getUserRole(userId)
                            .map(role -> role == Role.ADMIN)
                            .orElse(false);
    }

    private boolean isResourceOwner(String userId, String resourceId, String resourceType) {
        return permissionRepo.getResourceOwner(resourceId, resourceType)
                            .map(ownerId -> ownerId.equals(userId))
                            .orElse(false);
    }

    private Optional<Permission> getDirectPermission(String userId, String resourceId, String resourceType) {
        return permissionRepo.getDirectPermission(userId, resourceId, resourceType);
    }

    private Optional<Permission> getTeamPermission(String teamId, String resourceId, String resourceType) {
        return permissionRepo.getTeamPermission(teamId, resourceId, resourceType);
    }

    private boolean isTeamLeadWithAccessToMember(String userId, String resourceId, String resourceType) {
        Optional<String> resourceOwner = permissionRepo.getResourceOwner(resourceId, resourceType);
        if (resourceOwner.isEmpty()) return false;

        List<String> userTeams = teamRepo.getTeamsWhereUserIsLead(userId);
        for (String teamId : userTeams) {
            if (teamRepo.isUserInTeam(resourceOwner.get(), teamId)) {
                return true;
            }
        }
        return false;
    }
}

// Authorization Result - Immutable result object
public class AuthorizationResult {
    private final boolean authorized;
    private final String reason;
    private final Instant timestamp;

    private AuthorizationResult(boolean authorized, String reason) {
        this.authorized = authorized;
        this.reason = reason;
        this.timestamp = Instant.now();
    }

    public static AuthorizationResult granted(String reason) {
        return new AuthorizationResult(true, reason);
    }

    public static AuthorizationResult denied(String reason) {
        return new AuthorizationResult(false, reason);
    }

    public boolean isAuthorized() { return authorized; }
    public String getReason() { return reason; }
}

// Secure Controller with comprehensive authorization
@Path("/api/documents")
@Produces(MediaType.APPLICATION_JSON)
public class ProductionDocumentController {

    private static final Logger LOGGER = Logger.getLogger(ProductionDocumentController.class.getName());

    @Inject
    private AuthorizationService authService;

    @Inject
    private DocumentRepository documentRepo;

    @Inject
    private SecurityContext securityContext;

    @Inject
    private RateLimiter rateLimiter;

    @GET
    @Path("/{documentId}")
    public Response getDocument(@PathParam("documentId") String documentId,
                                @Context HttpHeaders headers) {

        String userId = getCurrentUserId();

        // Rate limiting check
        if (!rateLimiter.tryAcquire(userId, "document_read")) {
            LOGGER.warning(String.format("Rate limit exceeded: user=%s", userId));
            return Response.status(429)
                          .header("Retry-After", "60")
                          .entity("Rate limit exceeded").build();
        }

        // Input validation
        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST)
                          .entity("Invalid document ID format").build();
        }

        // Authorization check
        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.READ)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            // Return 404 instead of 403 to prevent resource enumeration
            return Response.status(Response.Status.NOT_FOUND)
                          .entity("Document not found").build();
        }

        // Fetch and return document
        try {
            Optional<Document> doc = documentRepo.findById(documentId);
            if (doc.isPresent()) {
                return Response.ok(doc.get())
                              .header("X-Content-Type-Options", "nosniff")
                              .header("Cache-Control", "private, no-store")
                              .build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (Exception e) {
            LOGGER.severe("Error fetching document: " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    @RolesAllowed({"ADMIN", "TEAM_LEAD", "MEMBER"})
    public Response deleteDocument(@PathParam("documentId") String documentId) {

        String userId = getCurrentUserId();

        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST).build();
        }

        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.DELETE)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Delete permission required").build();
        }

        try {
            // Soft delete with audit trail
            documentRepo.softDelete(documentId, userId);
            LOGGER.info(String.format("Document deleted: id=%s, by=%s, reason=%s", 
                       documentId, userId, authResult.getReason()));
            return Response.noContent().build();
        } catch (Exception e) {
            LOGGER.severe("Error deleting document: " + e.getMessage());
            return Response.serverError().build();
        }
    }

    private String getCurrentUserId() {
        return securityContext.getUserPrincipal().getName();
    }

    private boolean isValidUUID(String id) {
        try {
            java.util.UUID.fromString(id);
            return true;
        } catch (IllegalArgumentException e) {
            return false;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Gate** (handled by container/framework):
```java
@RolesAllowed({"ADMIN", "TEAM_LEAD", "MEMBER"})
public Response deleteDocument(...) {
    // Method only accessible to authenticated users with specific roles
}
```

2. **Resource-Level Authorization** (custom authorization service):
```java
AuthorizationResult authResult = authService.authorize(authRequest);
if (!authResult.isAuthorized()) {
    return Response.status(Response.Status.FORBIDDEN).build();
}
```

3. **Database-Level Enforcement** (defense if app logic bypassed):
```java
// Repository implementation includes user context
public Optional<Document> findByIdForUser(String docId, String userId) {
    String sql = "SELECT d.* FROM documents d " +
                "WHERE d.id = ? AND d.deleted_at IS NULL " +
                "AND EXISTS (SELECT 1 FROM permissions p " +
                "           WHERE p.resource_id = d.id AND p.user_id = ?)";
    // Even if authorization service is bypassed, DB enforces access
}
```

**Additional Protections**:

- **Rate limiting**: Prevents enumeration attacks and DoS
- **UUID resource IDs**: Non-sequential IDs prevent guessing
- **404 vs 403 strategy**: Return 404 for unauthorized reads to prevent resource discovery
- **Soft delete with audit**: Maintain audit trail, enable recovery
- **Security headers**: Prevent caching of sensitive data
- **Centralized authorization**: Single point of truth for permission logic
- **Comprehensive audit logging**: All access decisions logged with context for SIEM integration
- **Fail-closed design**: Default deny if any authorization component fails

