**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"encoding/hex"
	"html/template"
	"log"
	"net/http"
	"time"
)

func main() {
	http.HandleFunc("/login", secureLoginHandler)
	http.HandleFunc("/profile", secureProfileHandler)
	http.HandleFunc("/search", secureSearchHandler)
	http.ListenAndServe(":8080", nil)
}

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method == "POST" {
		username := r.FormValue("username")
		password := r.FormValue("password")

		if authenticateUser(username, password) {
			// SECURE: Cookie with all security flags
			cookie := &http.Cookie{
				Name:     "session_id",
				Value:    generateSecureSessionID(),
				Expires:  time.Now().Add(24 * time.Hour),
				Path:     "/",
				HttpOnly: true,                    // Prevents JavaScript access
				Secure:   true,                    // HTTPS only
				SameSite: http.SameSiteStrictMode, // Prevents CSRF
			}
			http.SetCookie(w, cookie)
			http.Redirect(w, r, "/profile", http.StatusFound)
			return
		}
	}

	// Use template for safe HTML rendering
	tmpl := template.Must(template.New("login").Parse(`
		<html><body>
			<form method="POST">
				<input name="username">
				<input name="password" type="password">
				<button>Login</button>
			</form>
		</body></html>
	`))
	tmpl.Execute(w, nil)
}

func secureSearchHandler(w http.ResponseWriter, r *http.Request) {
	query := r.URL.Query().Get("q")

	// SECURE: Use html/template for automatic escaping
	tmpl := template.Must(template.New("search").Parse(`
		<html><body>
			<h1>Search Results for: {{.Query}}</h1>
		</body></html>
	`))

	data := struct {
		Query string
	}{
		Query: query, // Template automatically escapes this
	}

	tmpl.Execute(w, data)
}

func secureProfileHandler(w http.ResponseWriter, r *http.Request) {
	_, err := r.Cookie("session_id")
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusFound)
		return
	}
	// Don't expose session ID in response
	w.Write([]byte("Welcome back!"))
}

func generateSecureSessionID() string {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		log.Fatal(err)
	}
	return hex.EncodeToString(bytes)
}
```

**Key Security Controls**:
- **HttpOnly flag**: Prevents JavaScript from accessing the cookie, blocking XSS-based cookie theft
- **Secure flag**: Ensures cookie is only transmitted over HTTPS, preventing MITM interception
- **SameSite=Strict**: Cookie not sent with cross-origin requests, mitigating CSRF attacks
- **html/template**: Go's template package automatically escapes HTML special characters, preventing XSS
- **Cryptographically secure session IDs**: Uses crypto/rand instead of predictable values

Excellent questions! Production environments require comprehensive session security that handles APIs, subdomains, and sophisticated attack vectors like session fixation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

type SessionStore struct {
	sessions map[string]*Session
	mu       sync.RWMutex
}

type Session struct {
	UserID       string
	CreatedAt    time.Time
	LastActivity time.Time
	IPAddress    string
	UserAgent    string
	IsValid      bool
}

type SecurityConfig struct {
	CookieDomain     string
	SecureCookies    bool
	SessionTimeout   time.Duration
	IdleTimeout      time.Duration
	EnableCSRFToken  bool
	AllowedOrigins   []string
}

var (
	sessionStore = &SessionStore{sessions: make(map[string]*Session)}
	config       *SecurityConfig
	logger       *log.Logger
)

func init() {
	logger = log.New(os.Stdout, "[SECURITY] ", log.LstdFlags|log.Lshortfile)

	// Environment-specific configuration
	config = &SecurityConfig{
		CookieDomain:   os.Getenv("COOKIE_DOMAIN"), // e.g., ".example.com" for subdomains
		SecureCookies:  os.Getenv("ENV") == "production",
		SessionTimeout: 24 * time.Hour,
		IdleTimeout:    30 * time.Minute,
		EnableCSRFToken: true,
		AllowedOrigins: strings.Split(os.Getenv("ALLOWED_ORIGINS"), ","),
	}
}

func main() {
	mux := http.NewServeMux()

	// Apply security middleware
	mux.Handle("/api/login", securityMiddleware(http.HandlerFunc(apiLoginHandler)))
	mux.Handle("/api/user", securityMiddleware(authRequired(http.HandlerFunc(apiUserHandler))))
	mux.Handle("/api/logout", securityMiddleware(authRequired(http.HandlerFunc(apiLogoutHandler))))

	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	logger.Println("Server starting on :8080")
	log.Fatal(server.ListenAndServeTLS("cert.pem", "key.pem"))
}

// Security middleware applies headers and validates requests
func securityMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Set security headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("X-XSS-Protection", "1; mode=block")
		w.Header().Set("Content-Security-Policy", "default-src 'self'; script-src 'self'")
		w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")

		// CORS validation for API endpoints
		origin := r.Header.Get("Origin")
		if origin != "" && !isAllowedOrigin(origin) {
			logger.Printf("Blocked request from unauthorized origin: %s", origin)
			http.Error(w, "Forbidden", http.StatusForbidden)
			return
		}

		next.ServeHTTP(w, r)
	})
}

// Authentication middleware with session validation
func authRequired(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		cookie, err := r.Cookie("session_id")
		if err != nil {
			logger.Printf("Missing session cookie from %s", r.RemoteAddr)
			sendJSONError(w, "Authentication required", http.StatusUnauthorized)
			return
		}

		session, valid := validateSession(cookie.Value, r)
		if !valid {
			logger.Printf("Invalid session attempt from %s", r.RemoteAddr)
			// Clear invalid cookie
			clearSessionCookie(w)
			sendJSONError(w, "Session expired or invalid", http.StatusUnauthorized)
			return
		}

		// Add session to request context
		ctx := context.WithValue(r.Context(), "session", session)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func apiLoginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		sendJSONError(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var creds struct {
		Username string `json:"username"`
		Password string `json:"password"`
	}

	if err := json.NewDecoder(r.Body).Decode(&creds); err != nil {
		sendJSONError(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	// Clear any existing session BEFORE authentication (prevents session fixation)
	if existingCookie, err := r.Cookie("session_id"); err == nil {
		invalidateSession(existingCookie.Value)
		clearSessionCookie(w)
		logger.Printf("Cleared pre-auth session for %s", r.RemoteAddr)
	}

	if !authenticateUser(creds.Username, creds.Password) {
		logger.Printf("Failed login attempt for user %s from %s", creds.Username, r.RemoteAddr)
		// Generic error to prevent user enumeration
		sendJSONError(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Generate NEW session after successful authentication
	sessionID := generateSecureToken(32)
	csrfToken := generateSecureToken(32)

	session := &Session{
		UserID:       creds.Username,
		CreatedAt:    time.Now(),
		LastActivity: time.Now(),
		IPAddress:    r.RemoteAddr,
		UserAgent:    r.UserAgent(),
		IsValid:      true,
	}

	sessionStore.mu.Lock()
	sessionStore.sessions[sessionID] = session
	sessionStore.mu.Unlock()

	// Set session cookie with all security flags
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    sessionID,
		Expires:  time.Now().Add(config.SessionTimeout),
		Path:     "/",
		Domain:   config.CookieDomain, // Allows subdomain sharing securely
		HttpOnly: true,
		Secure:   config.SecureCookies,
		SameSite: http.SameSiteStrictMode,
	})

	// Set CSRF token in separate cookie (readable by JS for API calls)
	http.SetCookie(w, &http.Cookie{
		Name:     "csrf_token",
		Value:    csrfToken,
		Expires:  time.Now().Add(config.SessionTimeout),
		Path:     "/",
		Domain:   config.CookieDomain,
		HttpOnly: false, // Must be readable by JavaScript
		Secure:   config.SecureCookies,
		SameSite: http.SameSiteStrictMode,
	})

	logger.Printf("Successful login for user %s from %s", creds.Username, r.RemoteAddr)

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"success": true,
		"message": "Login successful",
	})
}

func apiUserHandler(w http.ResponseWriter, r *http.Request) {
	session := r.Context().Value("session").(*Session)

	// Update last activity
	sessionStore.mu.Lock()
	session.LastActivity = time.Now()
	sessionStore.mu.Unlock()

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"user_id":    session.UserID,
		"created_at": session.CreatedAt,
	})
}

func apiLogoutHandler(w http.ResponseWriter, r *http.Request) {
	cookie, _ := r.Cookie("session_id")

	// Invalidate session server-side
	invalidateSession(cookie.Value)

	// Clear cookies
	clearSessionCookie(w)
	http.SetCookie(w, &http.Cookie{
		Name:     "csrf_token",
		Value:    "",
		Expires:  time.Unix(0, 0),
		MaxAge:   -1,
		Path:     "/",
		Domain:   config.CookieDomain,
		HttpOnly: false,
		Secure:   config.SecureCookies,
		SameSite: http.SameSiteStrictMode,
	})

	logger.Printf("Logout for session from %s", r.RemoteAddr)

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"message": "Logged out"})
}

func validateSession(sessionID string, r *http.Request) (*Session, bool) {
	sessionStore.mu.RLock()
	session, exists := sessionStore.sessions[sessionID]
	sessionStore.mu.RUnlock()

	if !exists || !session.IsValid {
		return nil, false
	}

	// Check absolute timeout
	if time.Since(session.CreatedAt) > config.SessionTimeout {
		logger.Printf("Session expired (absolute timeout) for user %s", session.UserID)
		invalidateSession(sessionID)
		return nil, false
	}

	// Check idle timeout
	if time.Since(session.LastActivity) > config.IdleTimeout {
		logger.Printf("Session expired (idle timeout) for user %s", session.UserID)
		invalidateSession(sessionID)
		return nil, false
	}

	// Optional: Validate IP binding (can cause issues with mobile users)
	// Uncomment for high-security applications:
	// if session.IPAddress != r.RemoteAddr {
	// 	logger.Printf("Session IP mismatch for user %s: expected %s, got %s",
	// 		session.UserID, session.IPAddress, r.RemoteAddr)
	// 	return nil, false
	// }

	return session, true
}

func invalidateSession(sessionID string) {
	sessionStore.mu.Lock()
	delete(sessionStore.sessions, sessionID)
	sessionStore.mu.Unlock()
}

func clearSessionCookie(w http.ResponseWriter) {
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Expires:  time.Unix(0, 0),
		MaxAge:   -1,
		Path:     "/",
		Domain:   config.CookieDomain,
		HttpOnly: true,
		Secure:   config.SecureCookies,
		SameSite: http.SameSiteStrictMode,
	})
}

func generateSecureToken(length int) string {
	bytes := make([]byte, length)
	if _, err := rand.Read(bytes); err != nil {
		logger.Fatalf("Failed to generate secure token: %v", err)
	}
	return hex.EncodeToString(bytes)
}

func isAllowedOrigin(origin string) bool {
	for _, allowed := range config.AllowedOrigins {
		if origin == allowed {
			return true
		}
	}
	return false
}

func sendJSONError(w http.ResponseWriter, message string, status int) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(map[string]string{"error": message})
}

func authenticateUser(username, password string) bool {
	// In production: use bcrypt and proper user database
	return username == "admin" && password == "securepassword"
}
```

**Defense in Depth Layers**:

1. **Session Fixation Prevention**:
```go
// Clear pre-auth session BEFORE authentication
if existingCookie, err := r.Cookie("session_id"); err == nil {
    invalidateSession(existingCookie.Value)
    clearSessionCookie(w)
}
// Generate NEW session ID only after successful auth
sessionID := generateSecureToken(32)
```

2. **Content Security Policy (CSP) Headers**:
```go
w.Header().Set("Content-Security-Policy", "default-src 'self'; script-src 'self'")
// Blocks inline scripts even if XSS payload is injected
```

3. **Multi-Factor Session Validation**:
```go
// Validate: existence, validity flag, absolute timeout, idle timeout
if !exists || !session.IsValid { return nil, false }
if time.Since(session.CreatedAt) > config.SessionTimeout { return nil, false }
if time.Since(session.LastActivity) > config.IdleTimeout { return nil, false }
```

**Additional Protections**:
- **Subdomain cookie sharing**: Use `Domain: ".example.com"` with Secure+SameSite flags to safely share sessions across subdomains
- **CSRF token pattern**: Separate non-HttpOnly CSRF cookie for JavaScript-based API calls while keeping session cookie HttpOnly
- **Server-side session invalidation**: Sessions stored server-side allow immediate revocation on logout or security events
- **Comprehensive audit logging**: All authentication events logged with IP, user agent, and timestamps for forensic analysis
- **Environment-specific security**: Different configurations for development vs production (Secure cookie flag)
- **Rate limiting consideration**: Add rate limiting middleware (e.g., `golang.org/x/time/rate`) to prevent brute force attacks
- **IP binding option**: For high-security apps, bind sessions to IP addresses (disabled by default due to mobile/VPN issues)

Managing PHP dependencies securely is critical because vulnerable packages are a primary attack vector. The Laravel Ignition RCE (CVE-2021-3129) demonstrated how a single vulnerable dev dependency led to thousands of compromised servers.

**VULNERABLE CONFIGURATION**:

```php
<?php
// composer.json - VULNERABLE: No version constraints, includes dev deps in production
{
    "name": "myapp/webapp",
    "require": {
        "laravel/framework": "*",
        "guzzlehttp/guzzle": "*",
        "phpmailer/phpmailer": "*"
    },
    "require-dev": {
        "facade/ignition": "*"
    }
}

// config/app.php - VULNERABLE: Debug mode in production
return [
    'debug' => true,  // NEVER in production!
    'env' => 'production',
];

// .env file deployed to production
APP_DEBUG=true
APP_ENV=production
IGNITION_SECRET_PATH=/var/www/html
```

**Attack Payload**:
```bash
# CVE-2021-3129 exploitation via Ignition
curl -X POST "http://target.com/_ignition/execute-solution" \
  -H "Content-Type: application/json" \
  -d '{"solution": "Facade\\Ignition\\Solutions\\MakeViewVariableOptionalSolution", 
       "parameters": {"viewFile": "phar://path/to/evil.phar", 
                      "variableName": "pwned"}}'

# Result: Remote code execution on the server
```

**Why This Is Dangerous**:
- Wildcard version constraints (`*`) allow automatic updates to vulnerable versions
- Dev dependencies with known RCE vulnerabilities deployed to production
- Debug mode exposes detailed error information and enables exploitation
- No security audit or vulnerability scanning in place

**SECURE VERSION**:

```php
