// composer.json - SECURE: Pinned versions, security audit
{
    "name": "myapp/webapp",
    "require": {
        "php": "^8.2",
        "laravel/framework": "^10.48.0",
        "guzzlehttp/guzzle": "^7.8.1",
        "phpmailer/phpmailer": "^6.9.1"
    },
    "require-dev": {
        "facade/ignition": "^2.17.7",
