        },
        "audit": {
            "abandoned": "fail"
        }
    },
    "scripts": {
        "security-check": "composer audit --format=json"
    }
}

// config/app.php - SECURE: Environment-based config
return [
    'debug' => env('APP_DEBUG', false),
    'env' => env('APP_ENV', 'production'),
];

// Production .env
APP_DEBUG=false
APP_ENV=production
```

